        'meta_title' => 'Vigan Heritage Church Route: A Calm Half-Day Walk | Resort Guru PH',
        'meta_description' => 'A slow half-day Vigan church route covering the metropolitan cathedral, Bantay Bell Tower, the old stone bridge, and the cemetery chapel.',
        'tags' => 'Vigan, Ilocos Sur, Heritage, Church, Walk',
        'cover_destination_key' => 'vigan',
